mapper.select:
SELECT cnum, ctitle, cwriter, CCONTENT, chit, cdate, cimgn, row_num FROM (SELECT cnum, ctitle, cwriter, CCONTENT, chit, cdate, cimgn, ROW_NUMBER() OVER(ORDER BY cnum desc) AS row_num FROM community
cwriter like '%' || #{searchValue} || '%'
ctitle like '%' || #{searchValue} || '%'
ccontent like '%' || #{searchValue} || '%'
) numbered_rows WHERE row_num BETWEEN #{begin} AND #{end}

mapper.update:
UPDATE community
SET
    ctitle = #{ctitle},
    ccontent = #{ccontent},
    cimgn = #{cimgn}
WHERE cnum = #{cnum}
